import React, { useEffect, useState } from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { SupabaseProvider, useSupabase } from './context/SupabaseContext';
import { ToastProvider } from './context/ToastContext';
import Layout from './components/layout/Layout';
import './index.css';

import LoginPage       from './pages/LoginPage';
import DashboardPage   from './pages/DashboardPage';
import VehiclesPage    from './pages/vehicles/VehiclesPage';
import DriversPage     from './pages/drivers/DriversPage';
import FuelPage        from './pages/fuel/FuelPage';
import MaintenancePage from './pages/maintenance/MaintenancePage';
import TripsPage       from './pages/trips/TripsPage';
import CompliancePage  from './pages/compliance/CompliancePage';
import IncidentsPage   from './pages/incidents/IncidentsPage';
import ReportsPage     from './pages/reports/ReportsPage';
import EmployeesPage   from './pages/hr/EmployeesPage';
import PayrollPage     from './pages/hr/PayrollPage';
import ExpensesPage    from './pages/hr/ExpensesPage';
import UsersPage       from './pages/UsersPage';

const SESSION_MS  = 8 * 60 * 60 * 1000;
const SESSION_KEY = 'fleet_login_time';

function AdminRoute({ isAdmin, children }) {
  return isAdmin ? children : <Navigate to="/dashboard" replace />;
}

function AccessGate({ status, onSignOut }) {
  return (
    <div style={{ minHeight:'100vh', background:'#0F172A', display:'flex', alignItems:'center', justifyContent:'center' }}>
      <div style={{ background:'#1E293B', border:'1px solid rgba(255,255,255,0.08)', borderRadius:16, padding:'48px 44px', maxWidth:400, width:'100%', textAlign:'center' }}>
        <div style={{ fontSize:48, marginBottom:16 }}>{status==='pending'?'⏳':'🚫'}</div>
        <h2 style={{ margin:'0 0 10px', color:'#fff' }}>{status==='pending'?'Awaiting Approval':'Access Denied'}</h2>
        <p style={{ fontSize:14, color:'rgba(255,255,255,0.4)', marginBottom:24 }}>{status==='pending'?'Your account is pending administrator approval.':'Your access has been revoked. Contact your administrator.'}</p>
        <button onClick={onSignOut} style={{ padding:'10px 24px', background:'#1D4ED8', color:'#fff', border:'none', borderRadius:8, fontSize:14, fontWeight:600, cursor:'pointer' }}>Sign Out</button>
      </div>
    </div>
  );
}

function AppRoutes() {
  const { client }  = useSupabase();
  const [session, setSession] = useState(undefined);
  const [profile, setProfile] = useState(undefined);

  const signOut = async () => {
    localStorage.removeItem(SESSION_KEY);
    await client.auth.signOut();
  };

  const isExpired = () => {
    const t = localStorage.getItem(SESSION_KEY);
    return !t || Date.now() - Number(t) > SESSION_MS;
  };

  useEffect(() => {
    if (!client) return;
    client.auth.getSession().then(({ data }) => {
      if (data.session && isExpired()) { signOut(); return; }
      setSession(data.session);
    });
    const { data:{ subscription } } = client.auth.onAuthStateChange((event, s) => {
      if (event === 'SIGNED_IN')  localStorage.setItem(SESSION_KEY, String(Date.now()));
      if (event === 'SIGNED_OUT') { localStorage.removeItem(SESSION_KEY); setProfile(null); }
      setSession(s);
    });
    return () => subscription.unsubscribe();
  }, [client]); // eslint-disable-line

  useEffect(() => {
    if (!client || !session) return;
    setProfile(undefined);
    client.from('profiles').select('*').eq('id', session.user.id).single().then(({ data }) => setProfile(data));
  }, [client, session]);

  if (!client) return (
    <div style={{ minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center', background:'#0F172A', color:'#FCA5A5', fontSize:14, textAlign:'center', padding:24 }}>
      ⚠️ Supabase not configured. Add REACT_APP_SUPABASE_URL and REACT_APP_SUPABASE_ANON_KEY to your .env file.
    </div>
  );

  if (session === undefined || (session && profile === undefined)) return (
    <div style={{ minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center', background:'#0F172A', color:'rgba(255,255,255,0.4)', fontSize:15 }}>Loading…</div>
  );

  if (!session) return <LoginPage />;
  if (profile && profile.status !== 'approved') return <AccessGate status={profile.status} onSignOut={signOut} />;

  const isAdmin = profile?.role === 'admin' || profile?.role === 'manager';

  return (
    <BrowserRouter>
      <Layout isAdmin={isAdmin} onSignOut={signOut} userProfile={profile}>
        <Routes>
          <Route path="/"             element={<Navigate to="/dashboard" replace />} />
          <Route path="/dashboard"    element={<DashboardPage isAdmin={isAdmin} />} />
          {/* Fleet */}
          <Route path="/vehicles"     element={<VehiclesPage isAdmin={isAdmin} />} />
          <Route path="/drivers"      element={<DriversPage isAdmin={isAdmin} />} />
          <Route path="/trips"        element={<TripsPage isAdmin={isAdmin} />} />
          {/* Operations */}
          <Route path="/fuel"         element={<FuelPage isAdmin={isAdmin} />} />
          <Route path="/maintenance"  element={<MaintenancePage isAdmin={isAdmin} />} />
          {/* Compliance */}
          <Route path="/compliance"   element={<CompliancePage isAdmin={isAdmin} />} />
          <Route path="/incidents"    element={<IncidentsPage isAdmin={isAdmin} />} />
          {/* HR */}
          <Route path="/hr/employees" element={<EmployeesPage isAdmin={isAdmin} />} />
          <Route path="/hr/payroll"   element={<AdminRoute isAdmin={isAdmin}><PayrollPage isAdmin={isAdmin} /></AdminRoute>} />
          <Route path="/hr/expenses"  element={<ExpensesPage isAdmin={isAdmin} />} />
          {/* Analytics */}
          <Route path="/reports"      element={<AdminRoute isAdmin={isAdmin}><ReportsPage /></AdminRoute>} />
          {/* Admin */}
          <Route path="/users"        element={<AdminRoute isAdmin={isAdmin}><UsersPage /></AdminRoute>} />
          <Route path="*"             element={<Navigate to="/dashboard" replace />} />
        </Routes>
      </Layout>
    </BrowserRouter>
  );
}

export default function App() {
  return (
    <SupabaseProvider>
      <ToastProvider>
        <AppRoutes />
      </ToastProvider>
    </SupabaseProvider>
  );
}
